import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"水","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/水.md","filePath":"ccc/生活/水.md"}`),a={name:`ccc/生活/水.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="水" tabindex="-1">水 <a class="header-anchor" href="#水" aria-label="Permalink to “水”">​</a></h1><h2 id="整体" tabindex="-1">整体 <a class="header-anchor" href="#整体" aria-label="Permalink to “整体”">​</a></h2><ul><li><p>前级过滤泥沙，大颗粒物，胶质物。</p><ul><li>推荐青柠超滤。</li></ul></li><li><p>软水机除钙镁离子，不容易产生水垢，龙头，淋浴间，热水器水箱，水管都会更干净。</p><ul><li><a href="https://post.smzdm.com/talk/p/a3dre4g7/" target="_blank" rel="noreferrer">DIY软水机</a>成本1K出头。<a href="https://s.click.taobao.com/U1ZSoKu?af=3&amp;union_lens=lensId%3APUB%401678160756%400b505e29_0be7_186ba2d0007_71a5%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">diy成品</a>大概近3K。厂货推荐<a href="https://item.taobao.com/item.htm?spm=a230r.1.14.6.173e5d7aMSeIyU&amp;id=672592229296&amp;ns=1&amp;abbucket=10#detail" target="_blank" rel="noreferrer">溢泰</a>，要8K。</li></ul></li><li><p>RO纯水机，产生纯净水。RO纯水机行文较为繁复，推荐细看后文-RO纯水机。</p><ul><li>推荐<a href="https://s.click.taobao.com/5nZ53Ku?af=3&amp;union_lens=lensId%3APUB%401679312519%40210720ba_0b1d_186fed37fd0_250f%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">北方水处理</a> DIY成品，<a href="https://post.smzdm.com/p/apx3ezew/" target="_blank" rel="noreferrer">参考网友拆箱</a>，<a href="https://s.click.taobao.com/FX738Lu?af=3&amp;union_lens=lensId%3APUB%401678162848%40212ccf0d_0ac8_186ba4ce937_04c6%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">希库科技</a>成品也可以考虑。厂货推荐小米。</li><li>厂牌复合滤芯产品，前级必须有青柠超滤或自己加PP棉滤芯，延长复合滤芯寿命，不然滤芯里的PP棉一两个月就黄了。多级滤芯，单换PP棉几块钱。</li><li>RO膜前级滤芯主要作用是保护RO膜，留着发黄的PP棉，实际上是得不偿失的。</li></ul></li></ul><h3 id="青柠超滤" tabindex="-1">青柠超滤 <a class="header-anchor" href="#青柠超滤" aria-label="Permalink to “青柠超滤”">​</a></h3><p><a href="https://www.bilibili.com/video/BV1yE411C7e6" target="_blank" rel="noreferrer">超滤膜丝拆洗</a></p><p>青柠超滤是效果最好的前级，一次性成本较高，但实际折算成本还可以，可以降低纯水机耗材成本，如省掉PP棉。</p><p>但是隔几个月要手动排污，甚至拆洗。如果把排污管接到马桶或专门的“拖把龙头”，生活用水就能实现自动冲洗膜丝。甚至一两年才需要拆洗。</p><blockquote><p>青柠后面不要接压力桶搞反冲洗。</p></blockquote><h3 id="软水机" tabindex="-1">软水机 <a class="header-anchor" href="#软水机" aria-label="Permalink to “软水机”">​</a></h3><p>软水机用离子交换树脂，把水里的钙镁置换成钠钾，软水机主要是定期自动用食盐水冲洗树脂，把钙镁再置换成钠钾，恢复树脂性能。</p><h2 id="ro纯水机" tabindex="-1">RO纯水机 <a class="header-anchor" href="#ro纯水机" aria-label="Permalink to “RO纯水机”">​</a></h2><p><a href="https://zhuanlan.zhihu.com/p/615540002" target="_blank" rel="noreferrer">知乎上写完的</a></p><p><a href="https://zhuanlan.zhihu.com/p/615540002" target="_blank" rel="noreferrer">知乎上写完的</a></p><p><a href="https://zhuanlan.zhihu.com/p/615540002" target="_blank" rel="noreferrer">知乎上写完的</a></p><p><a href="https://zhuanlan.zhihu.com/p/615540002" target="_blank" rel="noreferrer">知乎上写完的</a></p><p><a href="https://zhuanlan.zhihu.com/p/615540002" target="_blank" rel="noreferrer">知乎上写完的</a></p><h3 id="施工中" tabindex="-1">施工中 <a class="header-anchor" href="#施工中" aria-label="Permalink to “施工中”">​</a></h3><p>强烈推荐直接买 北方水处理 的DIY成品，所有配件选择都非常合理，都是有产品通过NSF认证的国际大牌。</p><p><a href="https://s.click.taobao.com/5nZ53Ku?af=3&amp;union_lens=lensId%3APUB%401679312519%40210720ba_0b1d_186fed37fd0_250f%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">北方水处理</a> 机架式用陶氏原装500g膜，大概1650左右。膜要560元左右。<a href="https://post.smzdm.com/p/apx3ezew/" target="_blank" rel="noreferrer">网友拆箱</a></p><blockquote><p>我因为要用国产RO膜只能自己组装，用美国陶氏膜，我就直接买北方水处理的成品了。我自己装，省掉第5级，主料辅料都用有NSF认证的品牌，不算RO膜成本在900左右。北方水处理不算RO膜，1100左右。走线没他的美观。</p></blockquote><p><a href="https://s.click.taobao.com/B6ehoKu?af=3&amp;union_lens=lensId%3APUB%401678157349%402132b6c1_0ac9_186b9f902df_7255%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">开泉净水</a>推荐用崧泉PP滤瓶的产品，最便宜的大概900左右。辅料用国产没去认证的。</p><p><a href="https://s.click.taobao.com/FX738Lu?af=3&amp;union_lens=lensId%3APUB%401678162848%40212ccf0d_0ac8_186ba4ce937_04c6%4001%40eyJmbG9vcklkIjo2NzY0MSwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIn0ie" target="_blank" rel="noreferrer">希库科技</a> 一些主料用的是比北方水处理更贵的，辅料没写。</p><p>六七百的用料堪忧，特别是几个打价格战的贴牌大王，基本都是ABS滤瓶，几块一个，关键没听说过食品级ABS塑料。崧泉PP滤瓶四五十一个，国产PP滤瓶，没去花钱认证的大概三十块一个。也因此，其他DIY成品基本不推荐了，不是是跟厂货一样，配件选择都藏着掖着，就是性价比还不如开泉净水。</p><h3 id="diy-diy成品-小米厂货。" tabindex="-1">diy，diy成品，小米厂货。 <a class="header-anchor" href="#diy-diy成品-小米厂货。" aria-label="Permalink to “diy，diy成品，小米厂货。”">​</a></h3><h3 id="滤芯" tabindex="-1">滤芯 <a class="header-anchor" href="#滤芯" aria-label="Permalink to “滤芯”">​</a></h3><p><strong>RO膜前级滤芯主要作用是保护RO膜，过滤影响RO膜寿命的物质。</strong></p><ul><li><p>PP棉，除颗粒物。</p></li><li><p>UDF颗粒活性炭，除氯，会掉渣。</p></li><li><p>CTO压铸活性炭，进一步除氯。挡前级UDF掉渣。</p></li><li><p>复合滤芯就是把这三级压成一根滤芯。</p><ul><li>买厂牌复合滤芯产品，前级必须有青柠超滤或自己加一根PP棉滤芯，延长复合滤芯寿命，不然滤芯里的PP棉一两个月就黄了。多级滤芯，单换PP棉几块钱。</li></ul></li><li><p>小米复合滤芯活动价还算合理。有NSF认证的溢泰，力晶一套三级滤芯也要100多块。</p><ul><li>多级滤芯厂货，PP棉，后置T33活性炭推荐买兼容滤芯。</li></ul></li><li><p>后置T33活性炭，接在RO膜纯水后面，主要作用是改善口感，但是会滋生细菌，推荐是三个月更换。我个人觉得DIY产品可以不加这一级。</p></li><li><p>超滤膜，可以除细菌，病毒，水生生物。</p></li><li><p>RO膜，过滤后几乎是纯净水。</p></li></ul><blockquote><p>一旦无氯，又不是纯水，就会大量滋生细菌。</p></blockquote><p>明白各种常见滤芯的作用，DIY是可以自由发挥的。比如前级有青柠超滤，可以把第一级滤瓶省掉或换成活性炭。也可以先过活性炭，超滤，用来洗菜洗水果，再过一些高端滤芯有NSF53认证初步除重金属之类的，再过RO。</p><p>用成本较低的RO膜，可以考虑PP棉+颗粒炭+PP棉这样较为便宜的前级。</p><h3 id="_75g有桶-vs-400g无桶-陈水难题" tabindex="-1">75g有桶 vs 400g无桶 陈水难题 <a class="header-anchor" href="#_75g有桶-vs-400g无桶-陈水难题" aria-label="Permalink to “75g有桶 vs 400g无桶 陈水难题”">​</a></h3><p>75g流量很小，要有一个压力桶储水，因为是纯水，即使细菌滋生也是比较有限的。<a href="https://www.bilibili.com/video/av936612526" target="_blank" rel="noreferrer">破拆压力桶视频</a>显示压力桶里头还是比较干净的。小流量滤芯的除盐率一般都相对会更高一些，成本因为寿命不一样，不好比较，理论上实际成本应该差不多。75g滤芯售价要便宜很多，用的泵之类的也可以便宜一些，动静也会更小。</p><p>大流量无桶机最大的短板是，纯水端的陈水会被污染，通常隔夜后，放水30s~50s之后才是纯水。市面上的零陈水方案基本都是加一个0.5g小压力桶，并联在RO膜出水口和进水口之间。每次出水后，额外做一些纯水，流到ro膜进水口。对于高频次少量取水而言，这样会有一点浪费水。</p><p>也可以考虑艾文水盒子，出水后检测TDS，高TDS的陈水作为废水排掉，纯净水才从水龙头出水。</p><h3 id="台式净饮机" tabindex="-1">台式净饮机 <a class="header-anchor" href="#台式净饮机" aria-label="Permalink to “台式净饮机”">​</a></h3><p>RO膜需要保持浸液防堵，这种净饮机受限于体积，基本只能用厂货滤芯，结果是成本高，寿命短。制的纯水存在纯水仓里，竟然还会滋生大量细菌，可见可靠性存疑，出水的时候用紫外线灯装模做样的照一下除菌，能除多少，值得怀疑。更有UV照射塑料等槽点。</p><p><a href="https://post.smzdm.com/p/553467/" target="_blank" rel="noreferrer">组装流程详细图文解说</a></p><p><a href="https://post.smzdm.com/p/agqd0xnm/" target="_blank" rel="noreferrer">水驱零陈水</a></p><p><a href="https://post.smzdm.com/p/awxqqqvk/" target="_blank" rel="noreferrer">如何确认NSF认证，一些NSF认证配件推荐</a></p><p><a href="https://post.smzdm.com/p/aqxpeqex/" target="_blank" rel="noreferrer">品牌滤芯余氯测试对比</a></p><p>废水流量调节</p><p>废水阀是关闭后，还会留个小洞的进水阀，流量不同既洞口大小不同。根据流量换算废水比准确性有限。比如1000cc，额定流量1L/min，400g的膜通常额定制水400加仑/天，折算1L/min，废水比1:1。但是这是理想状态，至少要膜前压力0.7MPa，增压泵流量2L/min，往往就达不到。</p><p>流量调节阀和进水阀组成的组合阀可以自由调节废水流量。调节流量阀实际改变的是膜前压力，而制水量和膜前压力正相关。以汇通膜为例，膜前压力在0.7MPa既俗称的7公斤水压。大概会达到1：1废水比。脱盐率95%。膜前压力越低，制水量就越少，废水比就越低。通常推荐高于0.35MPa。如果原水TDS很高，可以降低膜前压力到0.4MPa。</p>`,43)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};